			var $el = $(this)
			if($(this).attr("type") == "checkbox"){
				$(this).prop("checked", false);
			} else if($(this).attr("type") == "text"){
				$(this).val("");
			} else if($(this).attr("type") == "radio"){
				$(this).prop("selected", false);
			}
		});
		$("#"+id).find("select").each(function(){
			$(this).val("");
		});
